Answer:
Valid Amount: The amount must be positive.
Sufficient Funds: The balance must be enough to cover the withdrawal. 
Implementation in Java
This implementation uses IllegalArgumentException for invalid arguments and a custom InsufficientFundsException to represent the invalid state. 
java
// Custom exception for insufficient funds
class InsufficientFundsException extends Exception {
    public InsufficientFundsException(String message) {
        super(message);
    }
}

public class BankAccount {
    private double balance;

    public BankAccount(double initialBalance) {
        if (initialBalance < 0) {
            throw new IllegalArgumentException("Initial balance cannot be negative");
        }
        this.balance = initialBalance;
    }

    /**
     * Withdraws money from the account.
     * @param amount The amount to withdraw.
     * @throws IllegalArgumentException if amount <= 0.
     * @throws InsufficientFundsException if amount > current balance.
     */
    public void withdraw(double amount) throws InsufficientFundsException {
        // --- PRECONDITION CHECKS ---

        // 1. Check for valid amount (amount > 0)
        if (amount <= 0) {
            throw new IllegalArgumentException("Withdrawal amount must be positive.");
        }

        // 2. Check for sufficient funds (amount <= balance)
        if (amount > this.balance) {
            throw new InsufficientFundsException("Insufficient funds. Available: " + this.balance);
        }

        // --- ACTION ---
        this.balance -= amount;
        System.out.println("Withdrawal successful: $" + amount + ". New balance: $" + this.balance);
    }

    public double getBalance() {
        return balance;
    }
}

def most_consistent_store(sales_data, item):
    import statistics

    min_variance = float('inf')
    best_store = None

    for store, items in sales_data.items():
        if item in items:
            monthly_sales = items[item]
            if len(monthly_sales) > 1:
                variance = statistics.variance(monthly_sales)

                if variance < min_variance:
                    min_variance = variance
                    best_store = store

    return best_store

import socket

def calculate(expression):
    try:
        # Split the expression (e.g., "10 + 5" -> ['10', '+', '5'])
        parts = expression.split()
        if len(parts) != 3:
            return "Error: Invalid Format. Use 'num1 op num2'"

        num1 = float(parts[0])
        operator = parts[1]
        num2 = float(parts[2])

        if operator == '+': return str(num1 + num2)
        elif operator == '-': return str(num1 - num2)
        elif operator == '*': return str(num1 * num2)
        elif operator == '/':
            if num2 == 0: return "Error: Division by Zero"
            return str(num1 / num2)
        else:
            return "Error: Unknown Operator"
    except ValueError:
        return "Error: Invalid Numbers"

def start_server():
    host = '127.0.0.1' # Localhost
    port = 65432       # Arbitrary non-privileged port

    # Create TCP/IP Socket
    with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as server_socket:
        server_socket.bind((host, port))
        server_socket.listen()
        print(f"Calculator Server listening on {host}:{port}...")

        while True:
            # Accept new connection
            conn, addr = server_socket.accept()
            with conn:
                print(f"Connected by {addr}")
                while True:
                    data = conn.recv(1024).decode()
                    if not data or data.lower() == 'exit':
                        print("Client disconnected.")
                        break

                    print(f"Received: {data}")
                    result = calculate(data)
                    conn.sendall(result.encode())

if __name__ == "__main__":
    start_server()

